import{_ as e,o as r,c as i,a4 as l}from"./chunks/framework.BhEBm8_q.js";const k=JSON.parse('{"title":"Markdown 읽기","description":"","frontmatter":{},"headers":[],"relativePath":"06-markdown-reader.md","filePath":"06-markdown-reader.md"}'),n={name:"06-markdown-reader.md"};function d(o,a,t,h,s,m){return r(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="markdown-읽기" tabindex="-1">Markdown 읽기 <a class="header-anchor" href="#markdown-읽기" aria-label="Permalink to “Markdown 읽기”">​</a></h1><p><em>Markdown 렌더링 화면</em></p><p>Markdown 문서는 WebView 기반 리더로 열려, 서식이 풍부하게 표시됩니다. 렌더링에 필요한 요소는 앱에 포함되어 있어 인터넷 없이도 동작합니다(이미지 제외).</p><h2 id="지원하는-표현" tabindex="-1">지원하는 표현 <a class="header-anchor" href="#지원하는-표현" aria-label="Permalink to “지원하는 표현”">​</a></h2><ul><li>제목, 목록, 표</li><li>코드 블록과 구문 강조</li><li>Mermaid 다이어그램</li><li>Markwhen 타임라인</li><li>KaTeX 수식</li></ul><p>Mermaid와 KaTeX 자원은 외부 CDN이 아니라 앱에 번들로 들어 있어, 오프라인에서도 다이어그램과 수식이 그려집니다.</p><h2 id="안전한-렌더링" tabindex="-1">안전한 렌더링 <a class="header-anchor" href="#안전한-렌더링" aria-label="Permalink to “안전한 렌더링”">​</a></h2><p>Markdown은 화면에 그리기 전에 정제(sanitize)된 HTML로 변환됩니다.</p><ul><li>외부 스크립트, iframe, 인라인 이벤트 핸들러, 자동 화면 이동은 차단됩니다.</li><li>외부 링크는 자동으로 열리지 않고, 사용자가 직접 누른 경우에만 처리됩니다.</li><li>본문의 원격 이미지는 표시할 수 있습니다(이 경우 해당 이미지 주소로 네트워크 요청이 발생할 수 있습니다).</li></ul><h2 id="읽기-기능" tabindex="-1">읽기 기능 <a class="header-anchor" href="#읽기-기능" aria-label="Permalink to “읽기 기능”">​</a></h2><p>Markdown 문서도 다른 포맷과 같은 읽기 기능을 사용합니다.</p><ul><li>진행률 자동 저장과 복원</li><li>북마크와 다시 열기</li><li>현재 문서 검색과 보관함 본문 검색</li><li>세로 보기 자동 스크롤</li></ul><h2 id="범위" tabindex="-1">범위 <a class="header-anchor" href="#범위" aria-label="Permalink to “범위”">​</a></h2><p>이 리더는 읽기 전용입니다. Markdown 편집과 Markdown 위의 주석은 제공하지 않습니다. 메모가 필요하면 북마크와 노트를 활용하세요.</p>',14)])])}const p=e(n,[["render",d]]);export{k as __pageData,p as default};
